const results = [];
const items = $input.all();

for (const item of items) {
  const data = item.json;
  const elements = Array.isArray(data) ? data : (data.elements || [data]);

  for (const element of elements) {
    // 1. Handle Member Snapshot Data structure (which contains snapshotData array)
    if (element.snapshotData && Array.isArray(element.snapshotData)) {
      for (const post of element.snapshotData) {
        const shareLink = post.ShareLink || '';
        let id = '';
        const decoded = decodeURIComponent(shareLink);
        const match = decoded.match(/(urn:li:[a-zA-Z0-9_]+:[0-9]+)/);
        if (match) {
          id = match[1];
        } else {
          id = shareLink || Math.random().toString();
        }

        const content = post.ShareCommentary || '';
        const url = shareLink;
        const published_at = post.Date ? new Date(post.Date).toISOString() : new Date().toISOString();
        const author = 'me';

        results.push({
          id: id.toString(),
          author,
          content,
          url,
          published_at,
          processed: 0
        });
      }
      continue;
    }

    // 2. Handle original Changelog / direct structure
    const activity = element.activity || {};
    const author = activity.author || element.actor || '';
    const id = element.resourceId || element.id || '';
    if (!id) continue;

    let content = '';
    if (activity.specificContent && activity.specificContent['com.linkedin.ugc.ShareContent']) {
      const shareContent = activity.specificContent['com.linkedin.ugc.ShareContent'];
      if (shareContent.shareCommentary) {
        content = shareContent.shareCommentary.text || '';
      }
    } else if (activity.specificContent && activity.specificContent['com.linkedin.share.ShareContent']) {
      const shareContent = activity.specificContent['com.linkedin.share.ShareContent'];
      if (shareContent.shareCommentary) {
        content = shareContent.shareCommentary.text || '';
      }
    }

    const published_at_ms = (activity.created && activity.created.time) || activity.firstPublishedAt || element.processedAt || element.capturedAt;
    const published_at = published_at_ms ? new Date(published_at_ms).toISOString() : new Date().toISOString();
    const url = element.resourceUri ? `https://www.linkedin.com${element.resourceUri}` : '';

    results.push({
      id: id.toString(),
      author,
      content,
      url,
      published_at,
      processed: 0
    });
  }
}
return results;
